import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  FileText, 
  Clock, 
  CheckCircle, 
  AlertCircle, 
  Plus,
  Calendar,
  MapPin,
  Search,
  Filter,
  Tag,
  X,
  ChevronDown,
  ChevronLeft,
  ChevronRight
} from 'lucide-react';

const ComplaintList = () => {
  const { api } = useAuth();
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  // Filter states
  const [statusFilter, setStatusFilter] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [dateFilter, setDateFilter] = useState('');

  // Pagination state
  const [currentPage, setCurrentPage] = useState(0);
  const [totalPages, setTotalPages] = useState(0);
  const [totalElements, setTotalElements] = useState(0);
  const [pageSize, setPageSize] = useState(5); // Show 5 per page to see pagination with 10 items

  useEffect(() => {
    fetchComplaints();
  }, [currentPage, pageSize]); // Restore pagination dependency

  const handlePageChange = (newPage) => {
    if (newPage >= 0 && newPage < totalPages) {
      setCurrentPage(newPage);
    }
  };

  const handlePageSizeChange = (newSize) => {
    setPageSize(newSize);
    setCurrentPage(0); // Reset to first page when changing page size
  };

  const fetchComplaints = async () => {
    try {
      console.log('Fetching complaints with pagination:', { currentPage, pageSize });
      // Use the paginated API call
      const response = await api.get(`/complaints?page=${currentPage}&size=${pageSize}&sort=createdAt,desc`);
      console.log('Complaints response:', response);
      console.log('Response data:', response.data);

      // Handle paginated response
      if (response.data.content) {
        console.log('Using paginated response - content:', response.data.content);
        setComplaints(response.data.content);
        setTotalPages(response.data.totalPages);
        setTotalElements(response.data.totalElements);
        setCurrentPage(response.data.number);
      } else {
        // Fallback for non-paginated response
        const complaints = response.data || [];
        console.log('Using fallback response - complaints:', complaints);
        setComplaints(Array.isArray(complaints) ? complaints : []);
        // If we get all complaints at once, create pagination manually
        const totalItems = complaints.length;
        const calculatedTotalPages = Math.ceil(totalItems / pageSize);
        const startIndex = currentPage * pageSize;
        const endIndex = startIndex + pageSize;
        const paginatedComplaints = complaints.slice(startIndex, endIndex);

        setComplaints(paginatedComplaints);
        setTotalPages(calculatedTotalPages);
        setTotalElements(totalItems);
      }
    } catch (error) {
      console.error('Error fetching complaints:', error);
      console.error('Error response:', error.response);
      console.error('Error status:', error.response?.status);
      console.error('Error data:', error.response?.data);
      setComplaints([]);
      setTotalPages(0);
      setTotalElements(0);
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'PENDING': return 'bg-yellow-100 text-yellow-800';
      case 'IN_PROGRESS': return 'bg-blue-100 text-blue-800';
      case 'RESOLVED': return 'bg-green-100 text-green-800';
      case 'REJECTED': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'HIGH': return 'bg-red-100 text-red-800';
      case 'MEDIUM': return 'bg-orange-100 text-orange-800';
      case 'LOW': return 'bg-green-100 text-green-800';
      case 'URGENT': return 'bg-purple-100 text-purple-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getRelativeTime = (dateString) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffInSeconds = Math.floor((now - date) / 1000);

    if (diffInSeconds < 60) {
      return 'Just now';
    } else if (diffInSeconds < 3600) {
      const minutes = Math.floor(diffInSeconds / 60);
      return `${minutes} minute${minutes > 1 ? 's' : ''} ago`;
    } else if (diffInSeconds < 86400) {
      const hours = Math.floor(diffInSeconds / 3600);
      return `${hours} hour${hours > 1 ? 's' : ''} ago`;
    } else if (diffInSeconds < 604800) {
      const days = Math.floor(diffInSeconds / 86400);
      return `${days} day${days > 1 ? 's' : ''} ago`;
    } else if (diffInSeconds < 2592000) {
      const weeks = Math.floor(diffInSeconds / 604800);
      return `${weeks} week${weeks > 1 ? 's' : ''} ago`;
    } else {
      const months = Math.floor(diffInSeconds / 2592000);
      return `${months} month${months > 1 ? 's' : ''} ago`;
    }
  };

  const filteredComplaints = complaints.filter(complaint => {
    // Search filter
    const matchesSearch = searchTerm === '' || 
      complaint.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      complaint.description.toLowerCase().includes(searchTerm.toLowerCase());

    // Status filter
    const matchesStatus = statusFilter === '' || complaint.status === statusFilter;

    // Priority filter
    const matchesPriority = priorityFilter === '' || complaint.priority === priorityFilter;

    // Category filter
    const matchesCategory = categoryFilter === '' || 
      (complaint.assetCategory?.replace('_', ' ') || 'OTHER') === categoryFilter;

    // Date filter
    let matchesDate = true;
    if (dateFilter !== '') {
      // Parse complaint date more reliably
      const complaintDate = new Date(complaint.createdAt);
      const now = new Date();

      // Reset time to start of day for accurate comparison
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const complaintDay = new Date(complaintDate.getFullYear(), complaintDate.getMonth(), complaintDate.getDate());

      console.log('Date Filter Debug:', {
        dateFilter,
        complaintCreatedAt: complaint.createdAt,
        complaintDate: complaintDate.toISOString(),
        complaintDay: complaintDay.toISOString(),
        today: today.toISOString()
      });

      switch (dateFilter) {
        case 'today':
          matchesDate = complaintDay.getTime() === today.getTime();
          break;
        case 'yesterday':
          const yesterday = new Date(today);
          yesterday.setDate(yesterday.getDate() - 1);
          matchesDate = complaintDay.getTime() === yesterday.getTime();
          break;
        case 'week':
          // This week (Monday to Sunday)
          const startOfWeek = new Date(today);
          const dayOfWeek = today.getDay();
          const diff = today.getDate() - dayOfWeek + (dayOfWeek === 0 ? -6 : 1); // Adjust when day is Sunday
          startOfWeek.setDate(diff);
          matchesDate = complaintDay >= startOfWeek && complaintDay <= today;
          break;
        case 'last7days':
          const last7Days = new Date(today);
          last7Days.setDate(last7Days.getDate() - 7);
          matchesDate = complaintDay >= last7Days && complaintDay <= today;
          break;
        case 'month':
          // This month (1st to today)
          const startOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);
          matchesDate = complaintDay >= startOfMonth && complaintDay <= today;
          break;
        case 'last30days':
          const last30Days = new Date(today);
          last30Days.setDate(last30Days.getDate() - 30);
          matchesDate = complaintDay >= last30Days && complaintDay <= today;
          break;
        case 'last3months':
          const last3Months = new Date(today);
          last3Months.setMonth(last3Months.getMonth() - 3);
          matchesDate = complaintDay >= last3Months && complaintDay <= today;
          break;
        default:
          break;
      }
    }

    return matchesSearch && matchesStatus && matchesPriority && matchesCategory && matchesDate;
  });

  const clearFilters = () => {
    setSearchTerm('');
    setStatusFilter('');
    setPriorityFilter('');
    setCategoryFilter('');
    setDateFilter('');
  };

  const hasActiveFilters = searchTerm || statusFilter || priorityFilter || categoryFilter || dateFilter;

  // Get unique categories from complaints
  const categories = [...new Set(complaints.map(c => c.assetCategory?.replace('_', ' ') || 'OTHER'))].sort();

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header Section */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-700 rounded-xl p-8 text-white flex flex-col sm:flex-row sm:items-center sm:justify-between gap-6 overflow-hidden relative shadow-lg">
        <div className="relative z-10">
          <h1 className="text-3xl font-bold mb-2">My Complaints</h1>
          <p className="text-primary-100 italic">Manage and track your infrastructure complaints efficiently</p>
        </div>
        <Link
          to="/complaints/new"
          className="relative z-10 bg-white text-primary-600 px-6 py-3 rounded-lg font-bold hover:bg-primary-50 transition-all duration-300 shadow-md flex items-center justify-center space-x-2 border-b-4 border-primary-100 active:border-b-0 active:translate-y-1"
        >
          <Plus className="h-5 w-5" />
          <span>New Complaint</span>
        </Link>
        {/* Background decorative blur */}
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-48 w-48 rounded-full bg-white/10 blur-3xl"></div>
      </div>

      {/* Search and Filter */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex flex-col lg:flex-row gap-4">
          {/* Search Input */}
          <div className="flex-1 relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <Search className="h-5 w-5 text-gray-400" />
            </div>
            <input
              type="text"
              placeholder="Search complaints by title or description..."
              className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          {/* Filter Toggle Button */}
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`inline-flex items-center px-4 py-2 border rounded-lg transition-colors duration-200 ${
              hasActiveFilters 
                ? 'border-primary-300 bg-primary-50 text-primary-700' 
                : 'border-gray-300 text-gray-700 bg-white hover:bg-gray-50'
            }`}
          >
            <Filter className="mr-2 h-4 w-4" />
            Filters
            {hasActiveFilters && (
              <span className="ml-2 px-2 py-1 text-xs bg-primary-600 text-white rounded-full">
                {[statusFilter, priorityFilter, categoryFilter, dateFilter].filter(Boolean).length}
              </span>
            )}
            <ChevronDown className={`ml-2 h-4 w-4 transition-transform ${showFilters ? 'rotate-180' : ''}`} />
          </button>

          {/* Clear Filters Button */}
          {hasActiveFilters && (
            <button
              onClick={clearFilters}
              className="inline-flex items-center px-4 py-2 border border-gray-300 rounded-lg text-gray-700 bg-white hover:bg-gray-50 transition-colors duration-200"
            >
              <X className="mr-2 h-4 w-4" />
              Clear Filters
            </button>
          )}
        </div>

        {/* Filter Options */}
        {showFilters && (
          <div className="mt-6 pt-6 border-t border-gray-200">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Status Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Status</label>
                <select
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="">All Status</option>
                  <option value="PENDING">Pending</option>
                  <option value="IN_PROGRESS">In Progress</option>
                  <option value="RESOLVED">Resolved</option>
                  <option value="REJECTED">Rejected</option>
                </select>
              </div>

              {/* Priority Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Priority</label>
                <select
                  value={priorityFilter}
                  onChange={(e) => setPriorityFilter(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="">All Priorities</option>
                  <option value="URGENT">Urgent</option>
                  <option value="HIGH">High</option>
                  <option value="MEDIUM">Medium</option>
                  <option value="LOW">Low</option>
                </select>
              </div>

              {/* Category Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
                <select
                  value={categoryFilter}
                  onChange={(e) => setCategoryFilter(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="">All Categories</option>
                  {categories.map(category => (
                    <option key={category} value={category}>{category}</option>
                  ))}
                </select>
              </div>

              {/* Date Filter */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Date Range</label>
                <select
                  value={dateFilter}
                  onChange={(e) => setDateFilter(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                >
                  <option value="">All Time</option>
                  <option value="today">Today</option>
                  <option value="yesterday">Yesterday</option>
                  <option value="week">This Week</option>
                  <option value="last7days">Last 7 Days</option>
                  <option value="month">This Month</option>
                  <option value="last30days">Last 30 Days</option>
                  <option value="last3months">Last 3 Months</option>
                </select>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Complaints List */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">
            All Complaints ({filteredComplaints.length})
          </h2>
          {hasActiveFilters && (
            <span className="text-sm text-gray-500">
              Showing filtered results
            </span>
          )}
        </div>

        {filteredComplaints.length === 0 ? (
          <div className="text-center py-12">
            <FileText className="h-16 w-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium text-gray-900 mb-2">No complaints found</h3>
            <p className="text-gray-500 mb-6">
              {hasActiveFilters ? 'Try adjusting your filters or search terms' : 'Get started by creating your first complaint'}
            </p>
            {!hasActiveFilters && (
              <Link
                to="/complaints/new"
                className="inline-flex items-center px-6 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors duration-200"
              >
                <Plus className="mr-2 h-5 w-5" />
                Create Complaint
              </Link>
            )}
          </div>
        ) : (
          <div className="space-y-4">
            {filteredComplaints.map((complaint) => (
              <div
                key={complaint.id}
                className="border border-gray-200 rounded-lg p-6 hover:bg-gray-50 transition-colors duration-200"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-3">
                      <h3 className="text-lg font-medium text-gray-900">{complaint.title}</h3>
                      <div className="flex items-center space-x-2">
                        <span className="inline-flex items-center px-2 py-1 rounded bg-gray-100 text-gray-700 text-xs font-bold border border-gray-200">
                          <Tag className="h-3 w-3 mr-1" />
                          {complaint.assetCategory?.replace('_', ' ') || 'OTHER'}
                        </span>
                        <span className={`inline-flex items-center px-2 py-1 rounded text-xs font-bold ${getStatusColor(complaint.status)}`}>
                          {complaint.status.replace('_', ' ')}
                        </span>
                        <span className={`inline-flex items-center px-2 py-1 rounded text-xs font-bold ${getPriorityColor(complaint.priority)}`}>
                          {complaint.priority}
                        </span>
                      </div>
                    </div>

                    <p className="text-gray-600 mb-4 line-clamp-2">{complaint.description}</p>

                    <div className="flex flex-wrap items-center gap-4 text-sm text-gray-500">
                      <div className="flex items-center">
                        <Calendar className="h-4 w-4 mr-1" />
                        <span title="Created at: {new Date(complaint.createdAt).toLocaleString()}">
                          {new Date(complaint.createdAt).toLocaleDateString()}
                        </span>
                      </div>
                      {complaint.blockNumber && (
                        <div className="flex items-center">
                          <MapPin className="h-4 w-4 mr-1" />
                          Block {complaint.blockNumber}
                          {complaint.roomNumber && `, Room ${complaint.roomNumber}`}
                        </div>
                      )}
                      {/* Add relative time display */}
                      <div className="flex items-center text-xs">
                        <Clock className="h-3 w-3 mr-1" />
                        {getRelativeTime(complaint.createdAt)}
                      </div>
                    </div>
                  </div>

                  <div className="ml-4">
                    <Link
                      to={`/complaints/${complaint.id}`}
                      className="inline-flex items-center px-4 py-2 text-sm font-medium text-primary-600 bg-primary-50 rounded-lg hover:bg-primary-100 transition-colors duration-200"
                    >
                      View Details
                    </Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-700">
                Showing {currentPage * pageSize + 1} to {Math.min((currentPage + 1) * pageSize, totalElements)} of {totalElements} complaints
              </span>
            </div>

            <div className="flex items-center gap-2">
              {/* Page Size Selector */}
              <select
                value={pageSize}
                onChange={(e) => handlePageSizeChange(Number(e.target.value))}
                className="px-3 py-1 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
              >
                <option value={5}>5 per page</option>
                <option value={10}>10 per page</option>
                <option value={20}>20 per page</option>
                <option value={50}>50 per page</option>
              </select>

              {/* Pagination Controls */}
              <div className="flex items-center gap-1">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 0}
                  className="p-2 rounded-lg border border-gray-300 text-gray-500 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <ChevronLeft className="h-4 w-4" />
                </button>

                <div className="flex items-center gap-1">
                  {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                    let pageNum;
                    if (totalPages <= 5) {
                      pageNum = i;
                    } else if (currentPage < 3) {
                      pageNum = i;
                    } else if (currentPage >= totalPages - 3) {
                      pageNum = totalPages - 5 + i;
                    } else {
                      pageNum = currentPage - 2 + i;
                    }

                    return (
                      <button
                        key={pageNum}
                        onClick={() => handlePageChange(pageNum)}
                        className={`px-3 py-1 rounded-lg text-sm font-medium ${
                          currentPage === pageNum
                            ? 'bg-primary-600 text-white'
                            : 'border border-gray-300 text-gray-700 hover:bg-gray-50'
                        }`}
                      >
                        {pageNum + 1}
                      </button>
                    );
                  })}
                </div>

                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages - 1}
                  className="p-2 rounded-lg border border-gray-300 text-gray-500 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <ChevronRight className="h-4 w-4" />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ComplaintList;
